/* The Root Container sets the Base Font Size */
.miron-portal-container {
    /* Matches common book padding logic to align with text edges */
    width: 100%;
    max-width: 100%;
    margin: 2.5em 0;
    font-family: 'Poppins', sans-serif;
    font-size: ${baseFontSize}px; 
    position: relative;
    z-index: 100;
    box-sizing: border-box;
}

/* All children use 'em' to scale relative to the dynamic base */
.miron-question-card {
    background: transparent;
    border: none;
    border-radius: 0;
    padding: 0;
    box-shadow: none;
    color: inherit;
}

.q-text {
    font-family: serif; /* Force inheritance of book's primary font */
    font-size: 1.25em; 
    line-height: 1.5;
    margin-bottom: 1.2em;
    font-weight: 600;
}

