ops.replace_with:
// Hydrate Miron Challenges from Data Anchors
doc.querySelectorAll('.miron-challenge-anchor').forEach(anchor => {
    try {
        const questions = JSON.parse(anchor.getAttribute('data-questions'));
        anchor.innerHTML = questions.map(q => {
            const options = q.options || [];
            // Smart Layout Logic: If any option is > 30 chars, use vertical layout
            const isLong = options.some(opt => (opt.text || opt).length > 30);

            return `
                <div class="miron-question-card">
                    <div class="q-header">
                        <div class="miron-orb-mini"></div>
                        <span class="q-label">Miron Challenge</span>
                        <span class="q-points-badge">+5 Linkoins</span>
                    </div>
                    <div class="q-text">${q.text}</div>
                    <div class="q-options ${isLong ? 'vertical-layout' : ''}">
                        ${options.map(opt => `
                            <button class="q-opt-btn" onclick="this.parentElement.querySelectorAll('.q-opt-btn').forEach(b=>b.classList.remove('selected')); this.classList.add('selected')">
                                ${opt.text || opt}
                            </button>
                        `).join('')}
                    </div>
                    <button class="q-submit" onclick="this.innerText='Correct! +5 Linkoins'; this.style.background='#b1d34b'; this.style.color='#000';">Submit Answer</button>
                </div>
            `;
        }).join('');
    } catch (e) { console.error("Miron Hydration Error:", e); }
});

const mironCount = doc.querySelectorAll('.miron-question-card').length;
console.log(`[IFRAME] Dimensions: ${w}x${h}. Miron Challenges detected: ${mironCount}`);

